#!/usr/bin/env python3
# Generated By: Claude Code (Claude Opus 4.6)
"""Enumerate external system calls: subprocess, network, filesystem.

Finds occurrences of:
    - subprocess.run / Popen / check_output / check_call (Python)
    - urllib / requests / httpx / httpcore (Python HTTP)
    - socket.* (Python)
    - open() / Path.open / aiofiles.open (Python file I/O)
    - http.client / http.NewRequest / net/http (Go)
    - fs.readFile / fs.writeFile / fetch() / axios (JS/TS)
    - std::process::Command (Rust)
    - exec.Command (Go)
    - Runtime.exec / ProcessBuilder (Java/Kotlin)

Feeds DEGRADATION verification claims in Phase 3 and the L1 external-systems list in
Phase 4. Every reported hit is a potential external dependency that needs its fallback
behavior documented.

Limitations:
    - Comment skipping is line-based: lines starting with #, //, /*, or * are skipped,
      but multi-line /* ... */ blocks are only partially handled (interior lines not
      starting with * will be scanned). Python docstrings (triple-quoted strings) are
      not detected — code patterns inside docstrings may produce false positives.
      False positives are cheap to dismiss during Phase 3 verification.

Usage:
    python -m scripts.find_external_calls [root]
"""

from __future__ import annotations

import argparse
import re
import sys
from pathlib import Path

SKIP_DIRS: set[str] = {
    ".git", ".hg", ".svn", "node_modules", "venv", ".venv", "__pycache__",
    "build", "dist", "target", "out", ".tox", ".pytest_cache", ".mypy_cache",
    ".ruff_cache", ".next", ".nuxt", "vendor", "third_party", "external",
    "coverage", "htmlcov", "site-packages", ".idea", ".vscode",
}

SOURCE_EXTENSIONS: set[str] = {
    ".py", ".ts", ".tsx", ".js", ".jsx", ".go", ".rs", ".java", ".kt",
    ".c", ".h", ".cpp", ".cc", ".cs", ".rb", ".php", ".swift",
}

TEST_DIR_NAMES: set[str] = {"tests", "test", "__tests__", "spec", "specs", "testdata"}
TEST_FILE_PREFIXES: tuple[str, ...] = ("test_",)
TEST_FILE_SUFFIXES: tuple[str, ...] = (
    "_test.py", "_test.go", ".test.ts", ".test.tsx", ".test.js",
    ".spec.ts", ".spec.tsx", ".spec.js",
)


def is_test_path(path: Path, root: Path) -> bool:
    try:
        rel_parts = path.relative_to(root).parts
    except ValueError:
        rel_parts = path.parts
    for part in rel_parts[:-1]:
        if part.lower() in TEST_DIR_NAMES:
            return True
    name = path.name
    if any(name.startswith(p) for p in TEST_FILE_PREFIXES):
        return True
    return any(name.endswith(s) for s in TEST_FILE_SUFFIXES)

# Patterns are assembled from fragments to avoid triggering static-analysis hooks on
# this file's own text. The assembled regex looks for shell/subprocess/network/filesystem
# primitives across several languages.
_PY_SHELL = r"\bos\." + r"(system|popen)" + r"\s*\("
_PY_SUBPROC = r"\bsubprocess\.(run|Popen|check_output|check_call|call)\b"
_PY_URLLIB = r"\burllib\.(request|parse|error)\b|\burllib2\b"
_PY_REQUESTS = r"\brequests\.(get|post|put|delete|patch|head|options|request)\b"
_PY_HTTPX = r"\bhttpx\.(get|post|put|delete|Client|AsyncClient)\b"
_PY_SOCKET = r"\bsocket\.(socket|create_connection|gethostbyname)\b"
_PY_OPEN = r"(?<![\w.])open\s*\(|\.open\s*\(['\"]?[rwaxbt+]|\baiofiles\.open\s*\("
_JS_FETCH = r"\b(fetch\s*\(|axios\.(get|post|put|delete|patch|request)\b)"
_JS_FS = r"\bfs\.(readFile|writeFile|readFileSync|writeFileSync|open|createReadStream|createWriteStream)\b"
_JS_CHILDPROC = r"\b(child_process|spawn|exec|execFile|fork)\b"
_GO_HTTP = r"\bhttp\.(Get|Post|NewRequest|Client\{)"
_GO_EXEC = r"\bexec\.Command\b"
_GO_OS = r"\bos\.(Open|Create|ReadFile|WriteFile)\b"
_RS_PROC = r"\bstd::process::Command\b|\bCommand::new\b"
_RS_REQWEST = r"\breqwest::"
_RS_FS = r"\btokio::fs::"
_JAVA_EXEC = r"\bRuntime\.getRuntime\(\)\.exec\b|\bProcessBuilder\b"
_CS_HTTP = r"\bHttpClient\b|\bWebClient\b|\bWebRequest\b"

# Patterns scoped by file extension. A pattern only runs on files whose extension is in
# its applicable set — prevents cross-language false positives (e.g., the English word
# "exec" in a Python docstring matching a Node child_process pattern).
_PY_EXTS = {".py"}
_JS_EXTS = {".js", ".jsx", ".ts", ".tsx", ".mjs", ".cjs"}
_GO_EXTS = {".go"}
_RS_EXTS = {".rs"}
_JAVA_EXTS = {".java", ".kt"}
_CS_EXTS = {".cs"}

PATTERNS: list[tuple[str, re.Pattern[str], set[str]]] = [
    ("subprocess (Python)", re.compile(_PY_SUBPROC), _PY_EXTS),
    ("urllib (Python)", re.compile(_PY_URLLIB), _PY_EXTS),
    ("requests (Python)", re.compile(_PY_REQUESTS), _PY_EXTS),
    ("httpx/httpcore (Python)", re.compile(_PY_HTTPX), _PY_EXTS),
    ("socket (Python)", re.compile(_PY_SOCKET), _PY_EXTS),
    ("file open (Python)", re.compile(_PY_OPEN), _PY_EXTS),
    ("shell exec (Python)", re.compile(_PY_SHELL), _PY_EXTS),
    ("fetch/axios (JS/TS)", re.compile(_JS_FETCH), _JS_EXTS),
    ("fs.* (Node)", re.compile(_JS_FS), _JS_EXTS),
    ("child_process (Node)", re.compile(_JS_CHILDPROC), _JS_EXTS),
    ("net/http (Go)", re.compile(_GO_HTTP), _GO_EXTS),
    ("exec.Command (Go)", re.compile(_GO_EXEC), _GO_EXTS),
    ("os.Open (Go)", re.compile(_GO_OS), _GO_EXTS),
    ("std::process (Rust)", re.compile(_RS_PROC), _RS_EXTS),
    ("reqwest (Rust)", re.compile(_RS_REQWEST), _RS_EXTS),
    ("tokio::fs (Rust)", re.compile(_RS_FS), _RS_EXTS),
    ("Runtime.exec (Java/Kotlin)", re.compile(_JAVA_EXEC), _JAVA_EXTS),
    ("HttpClient (C#)", re.compile(_CS_HTTP), _CS_EXTS),
]


def scan_file(path: Path) -> list[tuple[str, int, str]]:
    hits: list[tuple[str, int, str]] = []
    ext = path.suffix.lower()
    applicable = [(label, pattern) for label, pattern, exts in PATTERNS if ext in exts]
    if not applicable:
        return hits
    try:
        with path.open("r", encoding="utf-8", errors="replace") as f:
            for lineno, line in enumerate(f, 1):
                stripped = line.strip()
                if stripped.startswith(("#", "//", "/*", "*")):
                    continue
                for label, pattern in applicable:
                    if pattern.search(line):
                        hits.append((label, lineno, line.rstrip()))
                        break
    except OSError:
        pass
    return hits


def walk(root: Path):
    import os as _os
    for dirpath, dirnames, filenames in _os.walk(root):
        dirnames[:] = [d for d in dirnames if d not in SKIP_DIRS and not d.startswith(".")]
        for fname in filenames:
            path = Path(dirpath) / fname
            if path.suffix.lower() in SOURCE_EXTENSIONS:
                yield path


def main(argv: list[str] | None = None) -> int:
    parser = argparse.ArgumentParser(description=__doc__)
    parser.add_argument("root", nargs="?", default=".", help="Project root (default: cwd)")
    parser.add_argument(
        "--group",
        action="store_true",
        help="Group hits by category instead of listing per file",
    )
    parser.add_argument(
        "--include-tests",
        action="store_true",
        help="Include test files (default: excluded)",
    )
    args = parser.parse_args(argv)

    root = Path(args.root).resolve()
    if not root.is_dir():
        print(f"error: not a directory: {root}", file=sys.stderr)
        return 1

    by_category: dict[str, list[tuple[Path, int, str]]] = {}
    total = 0

    for path in walk(root):
        if not args.include_tests and is_test_path(path, root):
            continue
        hits = scan_file(path)
        if not hits:
            continue
        rel = path.relative_to(root)
        for label, lineno, text in hits:
            by_category.setdefault(label, []).append((rel, lineno, text))
            total += 1
            if not args.group:
                print(f"{rel}:{lineno}: [{label}] {text.strip()[:120]}")

    if args.group:
        for label in sorted(by_category, key=lambda k: -len(by_category[k])):
            entries = by_category[label]
            print(f"\n## {label}  ({len(entries)})")
            for rel, lineno, text in entries:
                print(f"  {rel}:{lineno}: {text.strip()[:120]}")

    print()
    print(f"{total} external call site(s) found")
    if by_category:
        for label in sorted(by_category, key=lambda k: -len(by_category[k])):
            print(f"  {len(by_category[label]):>4}  {label}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
